// ============================================================
// RAG ESTRUTURADO — Formata ticket para embedding semântico rico
// Inclui: problema, causa, solução, categoria, tags
// ============================================================
const ticket = $('Lotes de 10').item.json;
const comments = $input.item.json.comments || [];

// Extrai a solução do último comentário público do agente
const comentariosPublicos = comments.filter(c => !c.public === false || c.public === true);
const solucao = comentariosPublicos.length > 1
  ? comentariosPublicos[comentariosPublicos.length - 1]?.body || ''
  : '';

// Detecta categoria pelo assunto e tags do ticket
const subject = (ticket.subject || '').toLowerCase();
const tags = ticket.tags || [];

let categoria = 'OUTROS';
if (subject.includes('pix') || tags.includes('pix'))                        categoria = 'PIX';
else if (subject.includes('boleto') || tags.includes('boleto'))             categoria = 'BOLETO';
else if (subject.includes('cartao') || subject.includes('cartão') || tags.includes('cartao')) categoria = 'CARTÃO';
else if (subject.includes('api') || subject.includes('webhook') || tags.includes('api')) categoria = 'API';
else if (subject.includes('saldo') || tags.includes('saldo'))               categoria = 'SALDO';
else if (subject.includes('fraude') || subject.includes('antifraude'))      categoria = 'ANTIFRAUDE';
else if (subject.includes('concilia') || tags.includes('conciliacao'))      categoria = 'CONCILIAÇÃO';
else if (subject.includes('onboarding') || subject.includes('kyc'))         categoria = 'ONBOARDING';

// Estrutura rica para embedding — inclui problema, causa inferida, solução e metadados
const problema = ticket.subject || '';
const descricao = ticket.description || '';
const prioridade = ticket.priority || 'normal';

// Texto para embedding (quanto mais rico, melhor a busca semântica)
const textoEmbedding = [
  `Categoria: ${categoria}`,
  `Problema: ${problema}`,
  `Descrição: ${descricao.substring(0, 400)}`,
  solucao ? `Solução aplicada: ${solucao.substring(0, 400)}` : '',
  tags.length ? `Tags: ${tags.join(', ')}` : ''
].filter(Boolean).join('\n');

return {
  ticket_id: String(ticket.id),
  problema: problema,
  descricao: descricao.substring(0, 500),
  solucao: solucao.substring(0, 500),
  categoria: categoria,
  prioridade: prioridade,
  tags: tags,
  status: ticket.status,
  created_at: ticket.created_at,
  updated_at: ticket.updated_at,
  texto_embedding: textoEmbedding
};

// Prepara payload para Pinecone com metadata estruturada (problema/causa/solução/tags)
const embedding = $input.item.json.data[0].embedding;
const ticket = $('Formatar RAG Estruturado').item.json;

return {
  vectors: [{
    id: `zendesk-${ticket.ticket_id}`,
    values: embedding,
    metadata: {
      ticket_id: ticket.ticket_id,
      problema: ticket.problema,
      descricao: ticket.descricao,
      solucao: ticket.solucao,
      categoria: ticket.categoria,
      prioridade: ticket.prioridade,
      tags: ticket.tags.join(', '),
      status: ticket.status,
      source: 'zendesk',
      updated_at: ticket.updated_at
    }
  }],
  namespace: 'fitbank-tickets'
};
